import React, { useState } from 'react';
import { ChevronRight, ChevronDown, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import './AuthModal.css';

const AuthModal = ({ isOpen, onClose }) => {
    const { login, register, requestRegisterOTP, verifyRegisterOTP, forgotPassword, resetPassword } = useAuth();
    const navigate = useNavigate();

    const [isLogin, setIsLogin] = useState(true);
    const [isHelpOpen, setIsHelpOpen] = useState(false);
    const [formData, setFormData] = useState({ email: '', phone: '', password: '', name: '', otp: '' });
    const [rememberMe, setRememberMe] = useState(false);
    const [error, setError] = useState('');
    const [isVerifying, setIsVerifying] = useState(false);
    const [isOtpMode, setIsOtpMode] = useState(false);
    const [isEmailVerified, setIsEmailVerified] = useState(false);
    const [timeLeft, setTimeLeft] = useState(30);
    const [showPassword, setShowPassword] = useState(false);
    const [showForgotPassword, setShowForgotPassword] = useState(false);
    const [forgotStep, setForgotStep] = useState(1); // 1: email, 2: otp/newpass

    React.useEffect(() => {
        let timer;
        if ((isOtpMode || (showForgotPassword && forgotStep === 2)) && timeLeft > 0) {
            timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
        } else if (timeLeft === 0 && (isOtpMode || (showForgotPassword && forgotStep === 2))) {
            setError("OTP has expired. Please use the resend button.");
        }
        return () => clearTimeout(timer);
    }, [isOtpMode, timeLeft, showForgotPassword, forgotStep]);

    if (!isOpen) return null;

    const handleSendRegisterOtp = async () => {
        if (!formData.email) {
            setError('Please enter your email to verify.');
            return;
        }
        setError('');
        setIsVerifying(true);
        const reqRes = await requestRegisterOTP(formData.email);
        setIsVerifying(false);
        if (reqRes.success) {
            setTimeLeft(30);
            setIsOtpMode(true);
            setError('');
        } else {
            setError(reqRes.msg);
        }
    };

    const handleVerifyRegisterOtp = async () => {
        if (!formData.otp) {
            setError('Please enter verification code.');
            return;
        }
        setError('');
        setIsVerifying(true);
        const res = await verifyRegisterOTP(formData.email, formData.otp);
        setIsVerifying(false);
        if (res.success) {
            setIsEmailVerified(true);
            setIsOtpMode(false);
            setError('');
        } else {
            setError(res.msg);
        }
    };

    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setError('');
        if (forgotStep === 1) {
            setIsVerifying(true);
            const res = await forgotPassword(formData.email);
            setIsVerifying(false);
            if (res.success) {
                setTimeLeft(30);
                setForgotStep(2);
                setError('');
            } else {
                setError(res.msg);
            }
        } else {
            setIsVerifying(true);
            const res = await resetPassword(formData.email, formData.otp, formData.password);
            setIsVerifying(false);
            if (res.success) {
                setForgotStep(1);
                setShowForgotPassword(false);
                setIsLogin(true);
                alert(res.msg);
            } else {
                setError(res.msg);
            }
        }
    };

    const handleResendForgotPassword = async () => {
        setError('');
        setIsVerifying(true);
        const res = await forgotPassword(formData.email);
        setIsVerifying(false);
        if (res.success) {
            setTimeLeft(30);
            setError('');
        } else {
            setError(res.msg);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        try {
            if (isLogin) {
                setIsVerifying(true);
                const res = await login(formData.email, formData.password, rememberMe);
                setIsVerifying(false);
                if (res.success) {
                    if (formData.email === 'shreenithya111@gmail.com') {
                        window.location.href = '/admin';
                        return;
                    }
                    onClose();
                } else {
                    setError(res.msg);
                }
            } else {
                if (!isEmailVerified) {
                    setError('Please verify your email first.');
                    return;
                }

                const phoneDigits = formData.phone.replace(/[\s\-\(\)\+]/g, '');
                if (!/^\d{10}$/.test(phoneDigits)) {
                    setError('Please enter a valid 10-digit mobile number.');
                    return;
                }

                setIsVerifying(true);
                const res = await register(formData.name, formData.email, formData.phone, formData.password, '', '', '', '', '');
                setIsVerifying(false);
                if (res.success) {
                    if (formData.email === 'shreenithya111@gmail.com') {
                        window.location.href = '/admin';
                        return;
                    }
                    onClose();
                } else {
                    setError(res.msg);
                }
            }
        } catch (err) {
            setError('An error occurred. Please try again.');
        }
    };

    const handleToggleMode = (loginMode) => {
        setIsLogin(loginMode);
        setIsOtpMode(false);
        setIsEmailVerified(false);
        setShowForgotPassword(false);
        setForgotStep(1);
        setError('');
        setFormData({ email: '', phone: '', password: '', name: '', otp: '' });
    };

    return (
        <div className="a-auth-overlay">
            <div className="a-auth-logo" onClick={onClose}>VENTHULIR</div>

            <div className="a-auth-card">
                <h1 className="a-auth-heading">
                    {showForgotPassword ? 'Reset Password' : (isLogin ? 'Sign in' : 'Create account')}
                </h1>

                {error && (
                    <div className="a-auth-error-alert">
                        <AlertCircle size={18} className="a-alert-icon" />
                        <div className="a-alert-content">
                            <h4>There was a problem</h4>
                            <p>{error}</p>
                        </div>
                    </div>
                )}

                <form onSubmit={showForgotPassword ? handleForgotPassword : handleSubmit} className="a-auth-form">
                    {showForgotPassword ? (
                        <div className="a-forgot-password-stack">
                            {forgotStep === 1 ? (
                                <div className="a-input-row">
                                    <label>Email Address</label>
                                    <input
                                        type="email"
                                        placeholder="Enter registered email"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        required
                                    />
                                </div>
                            ) : (
                                <div className="otp-box-standard">
                                    <label>Enter Verification Code</label>
                                    <div className="a-verify-group">
                                        <input
                                            type="text"
                                            placeholder="000000"
                                            maxLength="6"
                                            value={formData.otp}
                                            onChange={(e) => setFormData({ ...formData, otp: e.target.value })}
                                            required
                                            style={{ letterSpacing: '8px', fontSize: '20px' }}
                                        />
                                    </div>

                                    <div className="a-input-row" style={{ marginTop: '20px', marginBottom: 0 }}>
                                        <label>New Password</label>
                                        <div className="a-password-input-wrapper">
                                            <input
                                                type={showPassword ? "text" : "password"}
                                                placeholder="At least 6 characters"
                                                value={formData.password}
                                                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                                required
                                            />
                                            <button
                                                type="button"
                                                className="a-password-toggle-btn"
                                                onClick={() => setShowPassword(!showPassword)}
                                            >
                                                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                            </button>
                                        </div>
                                    </div>

                                    <div className="timer-resend-row">
                                        <span className="timer" style={{ color: timeLeft <= 10 ? '#c40000' : '#0a2e1f' }}>
                                            {timeLeft > 0 ? `${timeLeft}s remaining` : 'Code expired'}
                                        </span>
                                        <button
                                            type="button"
                                            onClick={handleResendForgotPassword}
                                            className="resend-btn"
                                        >
                                            Resend OTP?
                                        </button>
                                    </div>
                                </div>
                            )}
                            <button type="submit" disabled={isVerifying} className="a-button-primary">
                                {isVerifying ? 'Processing...' : (forgotStep === 1 ? 'Send Reset Code' : 'Reset Password')}
                            </button>
                            <button
                                type="button"
                                onClick={() => { setShowForgotPassword(false); setForgotStep(1); setError(''); }}
                                style={{ width: '100%', background: 'none', border: 'none', color: '#0066c0', marginTop: '15px', cursor: 'pointer', fontSize: '13px', fontWeight: 'bold' }}
                            >
                                Back to Sign In
                            </button>
                        </div>
                    ) : (
                        isLogin ? (
                            <>
                                <div className="a-input-row">
                                    <label htmlFor="email">Email Address</label>
                                    <input
                                        id="email"
                                        type="email"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        required
                                    />
                                </div>

                                <div className="a-input-row">
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <label htmlFor="password">Password</label>
                                        <button
                                            type="button"
                                            onClick={() => setShowForgotPassword(true)}
                                            style={{ background: 'none', border: 'none', color: '#0066c0', fontSize: '12px', cursor: 'pointer', padding: 0 }}
                                        >
                                            Forgot password?
                                        </button>
                                    </div>
                                    <div className="a-password-input-wrapper">
                                        <input
                                            id="password"
                                            type={showPassword ? "text" : "password"}
                                            value={formData.password}
                                            onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                            required
                                        />
                                        <button
                                            type="button"
                                            className="a-password-toggle-btn"
                                            onClick={() => setShowPassword(!showPassword)}
                                        >
                                            {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                        </button>
                                    </div>
                                </div>
                                <div className="a-remember-row">
                                    <input
                                        type="checkbox" id="remember"
                                        checked={rememberMe}
                                        onChange={(e) => setRememberMe(e.target.checked)}
                                    />
                                    <label htmlFor="remember">Keep me signed in</label>
                                </div>
                                <button type="submit" disabled={isVerifying} className="a-button-primary">
                                    {isVerifying ? 'Processing...' : 'Sign In'}
                                </button>
                            </>
                        ) : (
                            <div className="a-registration-form-stack">
                                <div className="a-input-row">
                                    <label htmlFor="name">Your name</label>
                                    <input id="name" type="text" placeholder="First and last name" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} required />
                                </div>

                                <div className="a-input-row">
                                    <label htmlFor="email">Email Address</label>
                                    <div className="a-verify-group">
                                        <input
                                            id="email-reg"
                                            type="email"
                                            placeholder="Enter email"
                                            value={formData.email}
                                            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                            disabled={isEmailVerified}
                                            required
                                        />
                                        {!isEmailVerified && !isOtpMode && (
                                            <button
                                                type="button"
                                                onClick={handleSendRegisterOtp}
                                                disabled={isVerifying || !formData.email}
                                                className="a-button-verify-inline"
                                            >
                                                Verify
                                            </button>
                                        )}
                                        {isEmailVerified && (
                                            <span className="a-verified-badge">
                                                Γ£ô Verified
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {isOtpMode && !isEmailVerified && (
                                    <div className="otp-box-standard">
                                        <label>Enter Verification Code</label>
                                        <div className="a-verify-group">
                                            <input type="text" placeholder="000000" maxLength="6" value={formData.otp} onChange={e => setFormData({ ...formData, otp: e.target.value })} />
                                            <button type="button" onClick={handleVerifyRegisterOtp} disabled={isVerifying} className="a-button-verify-inline">Validate</button>
                                        </div>
                                        <div className="timer-resend-row">
                                            <span className="timer" style={{ color: timeLeft <= 10 ? '#c40000' : '#0a2e1f' }}>
                                                {timeLeft > 0 ? `${timeLeft}s` : 'Expired'}
                                            </span>
                                            <button type="button" onClick={handleSendRegisterOtp} className="resend-btn">Resend OTP?</button>
                                        </div>
                                    </div>
                                )}

                                <div className="a-input-row">
                                    <label htmlFor="phone">Mobile phone number</label>
                                    <input id="phone" type="tel" placeholder="10-digit number" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} required />
                                </div>

                                <div className="a-input-row">
                                    <label htmlFor="password">Password</label>
                                    <div className="a-password-input-wrapper">
                                        <input id="password-reg" type={showPassword ? "text" : "password"} placeholder="At least 6 characters" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} required />
                                        <button type="button" className="a-password-toggle-btn" onClick={() => setShowPassword(!showPassword)}>{showPassword ? <EyeOff size={16} /> : <Eye size={16} />}</button>
                                    </div>
                                </div>

                                <button type="submit" disabled={isVerifying || !isEmailVerified} className="a-button-primary" style={{ marginTop: '10px' }}>
                                    {isVerifying ? 'Processing...' : 'Create Account'}
                                </button>
                            </div>
                        )
                    )}
                </form>

                <div className="a-auth-card-footer">
                    <p className="a-auth-legal">By continuing, you agree to Venthulir's <span>Conditions of Use</span> and <span>Privacy Notice</span>.</p>

                    <div className="a-auth-help-section">
                        <div className="a-help-trigger" onClick={() => setIsHelpOpen(!isHelpOpen)}>
                            {isHelpOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                            <span>Need help?</span>
                        </div>
                        {isHelpOpen && (
                            <div className="a-help-dropdown">
                                <span onClick={() => { setShowForgotPassword(true); setIsHelpOpen(false); }} style={{ cursor: 'pointer' }}>Forgot Password</span>
                                <a href="#issues">Other issues with Sign-In</a>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="a-auth-outer-footer">
                {isLogin && !showForgotPassword && (
                    <>
                        <div className="a-auth-divider"><h5>New to Venthulir?</h5></div>
                        <button type="button" className="a-button-secondary" onClick={() => handleToggleMode(false)}>Create your Venthulir account</button>
                    </>
                )}

                {!isLogin && !showForgotPassword && (
                    <div className="a-auth-switch-link">
                        Already have an account? <span onClick={() => handleToggleMode(true)}>Sign in <ChevronRight size={12} /></span>
                    </div>
                )}

                <button className="a-back-home-button" onClick={onClose}>CANCEL AND RETURN TO HOME</button>
            </div>
        </div>
    );
};

export default AuthModal;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Trash2, ShoppingBag, ArrowRight } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { toast } from 'react-toastify';

const CartDrawer = ({ isOpen, onClose }) => {
    const { cart, removeFromCart, clearCart } = useCart();

    const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

    const handleCheckout = () => {
        if (cart.length === 0) return toast.info("Your cart is empty!");

        toast.promise(
            new Promise((resolve) => setTimeout(resolve, 2000)),
            {
                pending: '≡ƒææ Initializing Venthulir Secure Checkout...',
                success: '≡ƒÜÇ Redirecting to Razorpay Secure Payment...',
                error: 'Γ¥î Checkout portal synchronization failed.'
            }
        ).then(() => {
            // Simulated Razorpay trigger
            alert("≡ƒææ Venthulir Royal Checkout System:\n\nIn a live production environment, this would now open the Razorpay Gateway for Γé╣" + subtotal + ".\n\nRequired Verification Flow:\n1. Server-side order_id created\n2. Signature verification on success\n3. PDF Invoice generation");
            clearCart();
            onClose();
        });
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[2000]"
                    />
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                        className="fixed top-0 right-0 h-full w-full max-w-[450px] bg-white z-[2001] shadow-2xl flex flex-col"
                    >
                        {/* Header */}
                        <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-[#1b4d3e] text-white">
                            <div className="flex items-center gap-3">
                                <ShoppingBag />
                                <h2 className="text-xl font-black italic font-serif">Venthulir Registry</h2>
                            </div>
                            <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X /></button>
                        </div>

                        {/* Items */}
                        <div className="flex-1 overflow-y-auto p-6 space-y-6">
                            {cart.length === 0 ? (
                                <div className="h-full flex flex-col items-center justify-center text-center opacity-50 space-y-4">
                                    <ShoppingBag size={64} className="text-[#1b4d3e]" />
                                    <p className="text-lg font-bold">Your registry is empty.</p>
                                    <button onClick={onClose} className="text-[#d4af37] font-bold underline">Begin Harvest Selection</button>
                                </div>
                            ) : (
                                cart.map((item, i) => (
                                    <div key={i} className="flex gap-4 group">
                                        <div className="w-20 h-20 bg-gray-100 rounded-lg overflow-hidden flex-shrink-0 border border-gray-100">
                                            <img src={(item.images && item.images[0]) || item.imageUrl || item.image} alt={item.name} className="w-full h-full object-contain bg-white" />
                                        </div>
                                        <div className="flex-1">
                                            <div className="flex justify-between">
                                                <div>
                                                    <h4 className="font-bold text-[#1b4d3e] line-clamp-1">{item.name}</h4>
                                                    {item.selectedVariant && (
                                                        <span className="text-[10px] bg-[#f0f9f4] text-[#1b4d3e] px-2 py-0.5 rounded font-black uppercase tracking-widest">{item.selectedVariant}</span>
                                                    )}
                                                </div>
                                                <button
                                                    onClick={() => removeFromCart(item._id || item.id, item.selectedVariant)}
                                                    className="text-gray-400 hover:text-red-500 transition-colors"
                                                ><Trash2 size={16} /></button>
                                            </div>
                                            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">{item.category}</p>
                                            <div className="flex justify-between items-center mt-2">
                                                <p className="text-sm font-bold text-gray-600">Γé╣{item.price} ├ù {item.quantity}</p>
                                                <p className="text-lg font-black text-[#1b4d3e]">Γé╣{item.price * item.quantity}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>

                        {/* Footer */}
                        <div className="p-8 bg-gray-50 border-t border-gray-200 space-y-6">
                            <div className="flex justify-between items-end">
                                <span className="text-sm font-bold text-gray-500 uppercase tracking-widest">Venthulir Subtotal</span>
                                <span className="text-3xl font-black text-[#1b4d3e]">Γé╣{subtotal}</span>
                            </div>
                            <p className="text-[11px] text-gray-400 italic">Shipping and royal duties calculated at secure checkout. 100% Organic certified delivery.</p>
                            <button
                                onClick={handleCheckout}
                                className="w-full py-5 bg-[#1b4d3e] text-[#d4af37] font-black text-sm tracking-[0.2em] uppercase flex items-center justify-center gap-3 hover:bg-[#0a2e1f] transition-all shadow-xl active:scale-[0.98]"
                            >
                                SECURE ROYAL CHECKOUT <ArrowRight size={18} />
                            </button>
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
};

export default CartDrawer;

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Leaf } from 'lucide-react';
import './CinematicBackground.css';

const CinematicBackground = () => {
    const [leaves, setLeaves] = useState([]);

    useEffect(() => {
        // Keep the falling leaves animation
        setLeaves(Array.from({ length: 15 }).map((_, i) => ({
            id: i,
            x: Math.random() * 100,
            delay: Math.random() * 20,
            duration: 10 + Math.random() * 10,
            scale: 0.5 + Math.random() * 0.7,
            rotation: Math.random() * 360
        })));
    }, []);

    return (
        <div className="at-nature-scene">
            <video
                className="nature-video"
                autoPlay
                loop
                muted
                playsInline
                poster="https://images.unsplash.com/photo-1441974231531-c6227db76b6e?q=80&w=2560&auto=format"
            >
                {/* Primary: Direct Remote Link (Pexels) */}
                <source src="https://videos.pexels.com/video-files/3843516/3843516-hd_1920_1080_25fps.mp4" type="video/mp4" />
                {/* Secondary: Local Fallback */}
                <source src="/videos/nature.mp4" type="video/mp4" />
            </video>

            {/* Overlays */}
            <div className="video-overlay-tint"></div>
            <div className="video-overlay-gradient"></div>

            {/* Particles */}
            {leaves.map((leaf) => (
                <motion.div
                    key={leaf.id}
                    className="feature-leaf"
                    initial={{ x: `${leaf.x}vw`, y: '-10vh', opacity: 0, rotate: 0 }}
                    animate={{
                        y: '110vh',
                        x: [`${leaf.x}vw`, `${leaf.x + 10}vw`, `${leaf.x - 10}vw`],
                        rotate: 360,
                        opacity: [0, 0.9, 0.9, 0]
                    }}
                    transition={{
                        duration: leaf.duration,
                        repeat: Infinity,
                        delay: leaf.delay,
                        ease: "linear"
                    }}
                >
                    <Leaf size={24} strokeWidth={1.5} />
                </motion.div>
            ))}
        </div>
    );
};

export default CinematicBackground;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useAppNavigation } from '../context/NavigationContext';
import './MotionLayer.css';

const MotionLayer = () => {
    const { appNavigate } = useAppNavigation();

    // The line-up of 3 students (products)
    const products = [
        { id: 'sambar', src: '/products/sambar.png', name: 'Traditional Sambar', tag: 'Authentic South Indian Blend' },
        { id: 'chilli', src: '/products/chilli.png', name: 'Original Salem Chilli', tag: 'Handpicked & Sun-Dried' },
        { id: 'coriander', src: '/products/coriander.png', name: 'Fresh Coriander', tag: 'Aromatic & Pure' }
    ];

    const [activeIndex, setActiveIndex] = useState(0);

    // Cycles the front-most item every 3.5 seconds
    useEffect(() => {
        const interval = setInterval(() => {
            setActiveIndex((current) => (current + 1) % products.length);
        }, 3500);
        return () => clearInterval(interval);
    }, [products.length]);

    // Calculates the "Student Line-up" position for exactly 3 items
    const getCardStyles = (queuePos) => {
        switch (queuePos) {
            case 0:
                // Front of the line, saluting! (Highlighted with border)
                return { x: 0, y: 15, scale: 1.05, zIndex: 10, opacity: 1, rotate: 0 };
            case 1:
                // 2nd in line, waiting securely behind
                return { x: 0, y: -60, scale: 0.85, zIndex: 9, opacity: 0.5, rotate: 0 };
            case 2:
                // Peels off to the side, fades out, and elegantly loops around to the back
                return { x: 250, y: -20, scale: 0.9, zIndex: 11, opacity: 0, rotate: 25 };
            default:
                return { x: 0, y: 0, scale: 0, opacity: 0 };
        }
    };

    const fadeUpVariants = {
        hidden: { opacity: 0, y: 40 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.8, ease: [0.16, 1, 0.3, 1] } }
    };

    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: { staggerChildren: 0.15, delayChildren: 0.1 }
        }
    };

    return (
        <section className="premium-hero-container">
            {/* Ambient Background Glow */}
            <div className="premium-glow-sphere"></div>

            <div className="premium-hero-content">
                {/* Left Side: Dramatic Typography */}
                <motion.div
                    className="hero-text-column"
                    variants={containerVariants}
                    initial="hidden"
                    animate="visible"
                >
                    <motion.div className="brand-eyebrow" variants={fadeUpVariants}>
                        <span className="organic-dot"></span> 100% ORGANIC & WOOD-PRESSED
                    </motion.div>

                    <motion.h1 className="hero-monumental-title" variants={fadeUpVariants}>
                        Rooted in <br />
                        <span className="text-highlight">Nature.</span>
                    </motion.h1>

                    <motion.p className="hero-sophisticated-desc" variants={fadeUpVariants}>
                        Discover the pure, unadulterated essence of native soils. From our cold-ground spices to pure essential oils, experience the Royal Venthulir standard.
                    </motion.p>

                    <motion.div className="hero-action-row" variants={fadeUpVariants}>
                        <button
                            className="premium-primary-btn"
                            onClick={() => {
                                document.getElementById('products')?.scrollIntoView({ behavior: 'smooth' });
                            }}
                        >
                            Explore Harvest
                        </button>
                        <button
                            className="premium-secondary-btn"
                            onClick={() => {
                                window.scrollTo(0, 0);
                                appNavigate('all-products')
                            }}
                        >
                            View All Products
                        </button>
                    </motion.div>
                </motion.div>

                {/* Right Side: The Student Line Queue */}
                <div className="hero-visual-column">
                    <div className="epic-stack-stage">
                        {products.map((p, i) => {
                            // Math logic to figure out where each card sits in the 0-4 queue based on the current active item
                            const queuePos = (i - activeIndex + products.length) % products.length;
                            return (
                                <motion.div
                                    key={p.id}
                                    className={`epic-stack-card ${queuePos === 0 ? 'active-salute' : ''}`}
                                    initial={false}
                                    animate={getCardStyles(queuePos)}
                                    transition={{ duration: 0.9, ease: [0.25, 1, 0.4, 1] }}
                                    onClick={() => setActiveIndex(i)}
                                >
                                    <div className="product-image-wrapper">
                                        <img src={p.src} alt={p.name} />
                                    </div>
                                </motion.div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Soft Grain Overlay for Luxury Editorial feel */}
            <div className="luxury-noise-overlay"></div>
        </section>
    );
};

export default MotionLayer;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Check, Heart, ShoppingBag, Leaf } from 'lucide-react';

const NotificationSystem = () => {
    const [notifications, setNotifications] = useState([]);

    useEffect(() => {
        window.addOrganicNotification = (msg, type = 'success') => {
            const id = Date.now();
            setNotifications(prev => [...prev, { id, msg, type }]);
            setTimeout(() => {
                setNotifications(prev => prev.filter(n => n.id !== id));
            }, 3000);
        };

        return () => {
            delete window.addOrganicNotification;
        };
    }, []);

    const getIcon = (type) => {
        switch (type) {
