import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '../context/CartContext';
import { ShoppingCart, Trash2, Plus, Minus, ShoppingBag, Leaf, ArrowLeft } from 'lucide-react';
import { useAppNavigation } from '../context/NavigationContext';
import './CartPage.css';

const CartPage = () => {
    const { cart, incrementQuantity, decrementQuantity, removeFromCart, clearCart, getTotalPrice, getTotalItems } = useCart();
    const { appNavigate } = useAppNavigation();

    return (
        <div className="cart-page-root">
            <div className="cart-container">
                {/* Header */}
                <motion.div
                    className="cart-header"
                    initial={{ opacity: 0, y: -20 }}
                    animate={{ opacity: 1, y: 0 }}
                >
                    <div className="header-left">
                        <ShoppingCart size={32} className="header-icon" />
                        <div>
                            <h1>Your Cart</h1>
                            <p>{cart.length} product{cart.length !== 1 ? 's' : ''} ΓÇó {getTotalItems()} total items</p>
                        </div>
                    </div>
                    <button onClick={() => appNavigate('home')} className="continue-shopping" style={{ background: 'none', border: 'none', cursor: 'pointer', outline: 'none' }}>
                        <ArrowLeft size={16} />
                        Continue Shopping
                    </button>
                </motion.div>

                {cart.length === 0 ? (
                    <motion.div
                        className="empty-cart"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                    >
                        <ShoppingBag size={80} />
                        <h2>Your cart is empty</h2>
                        <p>Add some organic treasures to get started!</p>
                        <button onClick={() => appNavigate('home')} className="shop-now-btn" style={{ background: '#0b3d2e', color: '#fff', padding: '10px 20px', borderRadius: '8px', border: 'none', cursor: 'pointer', outline: 'none', textDecoration: 'none' }}>
                            Browse Products
                        </button>
                    </motion.div>
                ) : (
                    <div className="cart-layout">
                        {/* Items List */}
                        <div className="cart-items-section">
                            <AnimatePresence>
                                {cart.map((item, index) => {
                                    const itemId = item._id || item.id;
                                    const variantLabel = item.selectedVariant;
                                    return (
                                        <motion.div
                                            key={`${itemId}-${variantLabel || 'default'}`}
                                            className="cart-item-card"
                                            layout
                                            initial={{ opacity: 0, y: 20 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, scale: 0.9 }}
                                            transition={{ delay: index * 0.05 }}
                                        >
                                            {/* Image */}
                                            <div className="item-image">
                                                <img src={item.imageUrl || item.image} alt={item.name} />
                                            </div>

                                            {/* Details */}
                                            <div className="item-details">
                                                <span className="item-category">{item.category}</span>
                                                <h3 className="item-name">{item.name}</h3>
                                                {variantLabel && <span className="item-variant" style={{ fontSize: '12px', background: '#ececec', padding: '2px 8px', borderRadius: '4px', fontWeight: 'bold' }}>{variantLabel}</span>}
                                                <p className="item-price">Γé╣{item.price}</p>
                                            </div>

                                            {/* Quantity Controls */}
                                            <div className="quantity-controls">
                                                <motion.button
                                                    className="qty-btn"
                                                    onClick={() => decrementQuantity(itemId, variantLabel)}
                                                    whileTap={{ scale: 0.9 }}
                                                >
                                                    <Minus size={14} />
                                                </motion.button>
                                                <motion.span
                                                    className="qty-value"
                                                    key={item.quantity}
                                                    initial={{ scale: 1.2 }}
                                                    animate={{ scale: 1 }}
                                                >
                                                    {item.quantity}
                                                </motion.span>
                                                <motion.button
                                                    className="qty-btn"
                                                    onClick={() => incrementQuantity(itemId, variantLabel)}
                                                    whileTap={{ scale: 0.9 }}
                                                >
                                                    <Plus size={14} />
                                                </motion.button>
                                            </div>

                                            {/* Subtotal */}
                                            <div className="item-subtotal">
                                                <span className="subtotal-label">Subtotal</span>
                                                <span className="subtotal-value">Γé╣{item.price * item.quantity}</span>
                                            </div>

                                            {/* Remove */}
                                            <motion.button
                                                className="remove-btn"
                                                onClick={() => removeFromCart(itemId, variantLabel)}
                                                whileHover={{ scale: 1.05 }}
                                                whileTap={{ scale: 0.95 }}
                                            >
                                                <Trash2 size={16} />
                                            </motion.button>
                                        </motion.div>
                                    );
                                })}
                            </AnimatePresence>
                        </div>

                        {/* Summary */}
                        <motion.div
                            className="order-summary"
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                        >
                            <div className="summary-header">
                                <Leaf size={20} />
                                <h2>Order Summary</h2>
                            </div>

                            <div className="summary-rows">
                                <div className="summary-row">
                                    <span>Subtotal ({getTotalItems()} items)</span>
                                    <span>Γé╣{getTotalPrice()}</span>
                                </div>
                                <div className="summary-row">
                                    <span>Shipping</span>
                                    <span className="free">FREE</span>
                                </div>
                                <div className="summary-row">
                                    <span>Eco Packaging</span>
                                    <span className="free">FREE</span>
                                </div>
                            </div>

                            <div className="summary-total">
                                <span>Total</span>
                                <span className="total-value">Γé╣{getTotalPrice()}</span>
                            </div>

                            <motion.button
                                className="checkout-btn"
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => appNavigate('checkout')}
                            >
                                Proceed to Checkout
                            </motion.button>

                            <button className="clear-cart-btn" onClick={clearCart}>
                                Clear Cart
                            </button>
                        </motion.div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default CartPage;

import React, { useState, useEffect } from 'react';
import { useAppNavigation } from '../context/NavigationContext';
import { ShieldCheck, CreditCard, Truck, ShoppingBag, ChevronRight, ArrowLeft, Lock } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import './CheckoutPage.css';

const CheckoutPage = ({ viewParams = {} }) => {
    const { appNavigate } = useAppNavigation();
    const { user, isAuthenticated, updateUser } = useAuth();

    const [product, setProduct] = useState(null);
    const [quantity, setQuantity] = useState(1);
    const [variant, setVariant] = useState(null);

    const [step, setStep] = useState(1); // 1: Shipping, 2: Payment, 3: Success
    const [shippingData, setShippingData] = useState({
        fullName: user?.name || '',
        address: user?.deliveryAddress?.address || '',
        city: user?.deliveryAddress?.city || '',
        state: user?.deliveryAddress?.state || '',
        zipCode: user?.deliveryAddress?.zipCode || '',
        phone: user?.phone || ''
    });
    const [paymentMethod, setPaymentMethod] = useState('card');
    const [isProcessing, setIsProcessing] = useState(false);
    const [couponInput, setCouponInput] = useState('');
    const [appliedCoupon, setAppliedCoupon] = useState(null);
    const [couponError, setCouponError] = useState('');
    const [isVerifyingCoupon, setIsVerifyingCoupon] = useState(false);

    useEffect(() => {
        if (!isAuthenticated) {
            appNavigate('auth', { redirectView: 'checkout', redirectParams: viewParams });
            return;
        }

        const productId = viewParams.productId || viewParams.id;
        const qty = parseInt(viewParams.quantity) || 1;
        const variantLabel = viewParams.variant;

        if (productId) {
            fetchProduct(productId, qty, variantLabel);
        } else {
            // Handle cart checkout?
            // For now, let's focus on "Buy Now"
            appNavigate('home');
        }
    }, [isAuthenticated, viewParams]);

    const fetchProduct = async (id, qty, variantLabel) => {
        try {
            const data = await api.get('/products');
            const found = data.find(p => p._id === id || String(p.id) === id);
            if (found) {
                setProduct(found);
                setQuantity(qty);
                if (variantLabel && found.variants) {
                    const v = found.variants.find(v => v.label === variantLabel);
                    setVariant(v);
                } else if (found.variants && found.variants.length > 0) {
                    setVariant(found.variants[0]);
                }
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleShippingSubmit = async (e) => {
        e.preventDefault();
        try {
            const res = await api.put('/auth/address', {
                address: shippingData.address,
                city: shippingData.city,
                state: shippingData.state,
                zipCode: shippingData.zipCode
            });
            if (res.deliveryAddress) {
                updateUser({ ...user, deliveryAddress: res.deliveryAddress });
            }
        } catch (err) {
            console.error('Quietly failed to save address to profile', err);
        }
        setStep(2);
    };

    const handlePlaceOrder = async () => {
        setIsProcessing(true);
        try {
            const orderData = {
                customerName: shippingData.fullName,
                customerEmail: user.email,
                items: [{ product: product._id || product.id, name: product.name, variant: variant?.label, quantity, price: variant ? variant.price : product.price }],
                totalAmount: total,
                couponCode: appliedCoupon ? appliedCoupon.code : null
            };
            await api.post('/coupons/checkout', orderData);
            setStep(3);
        } catch (err) {
            console.error('Order Failed:', err);
            alert('Order failed to process. Please try again.');
        } finally {
            setIsProcessing(false);
        }
    };

    const handleApplyCoupon = async () => {
        if (!couponInput.trim()) return;
        setIsVerifyingCoupon(true);
        setCouponError('');
        try {
            const res = await api.post('/coupons/validate', { code: couponInput, productId: product._id || product.id });
            if (res.valid) {
                setAppliedCoupon({ code: res.couponCode, discountPercentage: res.discountPercentage });
                setCouponInput('');
            }
        } catch (err) {
            setCouponError(err.response?.data?.error || err.message || 'Invalid coupon');
            setAppliedCoupon(null);
        } finally {
            setIsVerifyingCoupon(false);
        }
    };

    const handleRemoveCoupon = () => {
        setAppliedCoupon(null);
        setCouponError('');
    };

    if (!product) return <div className="checkout-loading">Preparing your harvest...</div>;

    const subtotal = (variant ? variant.price : product.price) * quantity;
    const discountAmount = appliedCoupon ? (subtotal * appliedCoupon.discountPercentage) / 100 : 0;
    const afterDiscountSubtotal = subtotal - discountAmount;
    const shipping = afterDiscountSubtotal > 1000 ? 0 : 100;
    const total = afterDiscountSubtotal + shipping;

    if (step === 3) {
        return (
            <div className="order-success-container">
                <div className="success-content">
                    <div className="success-icon-wrap">
                        <ShieldCheck size={64} color="#0b3d2e" />
                    </div>
                    <h1>Order Placed Successfully!</h1>
                    <p>Thank you, {user?.name}. Your royal harvest is being prepared.</p>
                    <div className="order-summary-box">
                        <p>Order ID: #VT-{Math.floor(100000 + Math.random() * 900000)}</p>
                        <p>Estimated Delivery: 3-5 Business Days</p>
                    </div>
                    <button className="primary-checkout-btn" onClick={() => appNavigate('home')}>Back to Sanctuary</button>
                </div>
            </div>
        );
    }

    return (
        <div className="checkout-page-root">
            <header className="checkout-header">
                <div className="checkout-header-inner">
                    <button className="back-link" onClick={() => appNavigate('home')}>
                        <ArrowLeft size={18} /> Back
                    </button>
                    <div className="checkout-logo">VENTHULIR</div>
                    <div className="security-badge">
                        <Lock size={14} /> 256-bit SSL Secure
                    </div>
                </div>
            </header>

            <main className="checkout-main">
                <div className="checkout-grid">
                    <div className="checkout-form-container">
                        <div className="checkout-stepper">
                            <div className={`step-item ${step >= 1 ? 'active' : ''}`}>Shipping</div>
                            <div className="step-divider"></div>
                            <div className={`step-item ${step >= 2 ? 'active' : ''}`}>Payment</div>
                        </div>

                        {step === 1 ? (
                            <div className="shipping-section animate-fade-in">
                                <h2>Shipping Information</h2>
                                <p style={{ fontSize: '13px', color: '#64748b', marginBottom: '20px' }}>Your address will be saved for future orders.</p>
                                <form className="checkout-form" onSubmit={handleShippingSubmit}>
                                    <div className="input-group">
                                        <label>Full Name</label>
                                        <input required type="text" value={shippingData.fullName} onChange={e => setShippingData({ ...shippingData, fullName: e.target.value })} />
                                    </div>
                                    <div className="input-group">
                                        <label>Street Address</label>
                                        <input required type="text" value={shippingData.address} onChange={e => setShippingData({ ...shippingData, address: e.target.value })} />
                                    </div>
                                    <div className="input-row">
                                        <div className="input-group">
                                            <label>City</label>
                                            <input required type="text" value={shippingData.city} onChange={e => setShippingData({ ...shippingData, city: e.target.value })} />
                                        </div>
                                        <div className="input-group">
                                            <label>State</label>
                                            <input required type="text" value={shippingData.state} onChange={e => setShippingData({ ...shippingData, state: e.target.value })} />
                                        </div>
                                    </div>
                                    <div className="input-row">
                                        <div className="input-group">
                                            <label>ZIP Code</label>
                                            <input required type="text" value={shippingData.zipCode} onChange={e => setShippingData({ ...shippingData, zipCode: e.target.value })} />
                                        </div>
                                        <div className="input-group">
                                            <label>Phone Number</label>
                                            <input required type="tel" value={shippingData.phone} onChange={e => setShippingData({ ...shippingData, phone: e.target.value })} />
                                        </div>
                                    </div>
                                    <button type="submit" className="primary-checkout-btn">Continue to Payment <ChevronRight size={18} /></button>
                                </form>
                            </div>
                        ) : (
                            <div className="payment-section animate-fade-in">
                                <h2>Payment Method</h2>
                                <div className="payment-options">
                                    <div className={`payment-card ${paymentMethod === 'card' ? 'selected' : ''}`} onClick={() => setPaymentMethod('card')}>
                                        <CreditCard size={24} />
                                        <span>Credit / Debit Card</span>
                                    </div>
                                    <div className={`payment-card ${paymentMethod === 'upi' ? 'selected' : ''}`} onClick={() => setPaymentMethod('upi')}>
                                        <div className="upi-logo">UPI</div>
                                        <span>PhonePe / Google Pay</span>
                                    </div>
                                    <div className={`payment-card ${paymentMethod === 'cod' ? 'selected' : ''}`} onClick={() => setPaymentMethod('cod')}>
                                        <Truck size={24} />
                                        <span>Cash on Delivery</span>
                                    </div>
                                </div>

                                {paymentMethod === 'card' && (
                                    <div className="card-details animate-slide-down">
                                        <div className="input-group">
                                            <label>Card Number</label>
                                            <input type="text" placeholder="xxxx xxxx xxxx xxxx" />
                                        </div>
                                        <div className="input-row">
                                            <div className="input-group">
                                                <label>Expiry Date</label>
                                                <input type="text" placeholder="MM/YY" />
                                            </div>
                                            <div className="input-group">
                                                <label>CVV</label>
                                                <input type="password" placeholder="***" />
                                            </div>
                                        </div>
                                    </div>
                                )}

                                <div className="order-actions">
                                    <button className="secondary-checkout-btn" onClick={() => setStep(1)}>Back to Shipping</button>
                                    <button
                                        className="primary-checkout-btn"
                                        onClick={handlePlaceOrder}
                                        disabled={isProcessing}
                                    >
                                        {isProcessing ? 'Verifying...' : `Pay Γé╣${total.toLocaleString()}`}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="checkout-summary-container">
                        <div className="summary-card">
                            <h3>Order Summary</h3>
                            <div className="summary-item product-preview">
                                <img src={product.imageUrl || product.images?.[0]} alt={product.name} />
                                <div className="item-details">
                                    <h4>{product.name}</h4>
                                    <p>{variant?.label || 'Standard'}</p>
                                    <p>Qty: {quantity}</p>
                                </div>
                                <div className="item-price">Γé╣{subtotal.toLocaleString()}</div>
                            </div>

                            <div className="summary-divider"></div>

                            <div className="summary-row">
                                <span>Subtotal</span>
                                <span>Γé╣{subtotal.toLocaleString()}</span>
                            </div>
                            {appliedCoupon && (
                                <div className="summary-row" style={{ color: '#22c55e' }}>
                                    <span>Discount ({appliedCoupon.discountPercentage}%)</span>
                                    <span>- Γé╣{discountAmount.toLocaleString()}</span>
                                </div>
                            )}
                            <div className="summary-row">
                                <span>Shipping</span>
                                <span>{shipping === 0 ? 'FREE' : `Γé╣${shipping}`}</span>
                            </div>
                            <div className="summary-row total">
                                <span>Total</span>
                                <span>Γé╣{total.toLocaleString()}</span>
                            </div>

                            <div className="coupon-entry-section" style={{ marginTop: '20px', borderTop: '1px dashed #e2e8f0', paddingTop: '20px' }}>
                                {appliedCoupon ? (
                                    <div style={{ background: '#dcfce7', padding: '10px', borderRadius: '8px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <div style={{ color: '#166534', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                            <ShieldCheck size={16} /> {appliedCoupon.code} Applied
                                        </div>
                                        <button onClick={handleRemoveCoupon} style={{ background: 'none', border: 'none', color: '#ef4444', fontSize: '12px', cursor: 'pointer', fontWeight: 'bold' }}>Remove</button>
                                    </div>
                                ) : (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                        <div style={{ display: 'flex', gap: '10px' }}>
                                            <input
                                                type="text"
                                                placeholder="Enter Coupon Code"
                                                value={couponInput}
                                                onChange={e => setCouponInput(e.target.value)}
                                                style={{ flex: 1, padding: '10px', borderRadius: '8px', border: '1px solid #cbd5e1', outline: 'none', textTransform: 'uppercase' }}
                                            />
                                            <button
                                                onClick={handleApplyCoupon}
                                                disabled={isVerifyingCoupon || !couponInput.trim()}
                                                style={{ padding: '10px 15px', background: '#0b3d2e', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', opacity: isVerifyingCoupon || !couponInput.trim() ? 0.7 : 1 }}
                                            >
                                                {isVerifyingCoupon ? '...' : 'Apply'}
                                            </button>
                                        </div>
                                        {couponError && <span style={{ color: '#ef4444', fontSize: '12px', fontWeight: 'bold' }}>{couponError}</span>}
                                    </div>
                                )}
                            </div>

                            <div className="guarantee-box">
                                <ShieldCheck size={18} />
                                <span>100% Satisfaction Guaranteed</span>
                            </div>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
};

export default CheckoutPage;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import OrderTracking from '../components/OrderTracking';
import InvoiceModal from '../components/InvoiceModal';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingBag, ChevronRight, FileText, Settings, LogOut, Package, ShieldQuestion, Send, LayoutDashboard } from 'lucide-react';
import './CustomerPage.css';

const CustomerPage = () => {
    const { user, logout } = useAuth();
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [isInvoiceOpen, setIsInvoiceOpen] = useState(false);
    const [isMessageModalOpen, setIsMessageModalOpen] = useState(false);
    const [messageText, setMessageText] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [grievances, setGrievances] = useState([]);
    const [activeSection, setActiveSection] = useState('Dashboard');

    const [profileAddress, setProfileAddress] = useState({
        address: user?.deliveryAddress?.address || '',
        city: user?.deliveryAddress?.city || '',
        state: user?.deliveryAddress?.state || '',
        zipCode: user?.deliveryAddress?.zipCode || '',
    });
    const [profileDetails, setProfileDetails] = useState({
        name: user?.name || '',
        phone: user?.phone || '',
    });
    const [isUpdatingAddress, setIsUpdatingAddress] = useState(false);
    const [isUpdatingProfile, setIsUpdatingProfile] = useState(false);
    const { updateUser } = useAuth();

    useEffect(() => {
        if (user?.email) {
            fetchGrievances();
        }
        if (user?.deliveryAddress) {
            setProfileAddress({
                address: user.deliveryAddress.address || '',
                city: user.deliveryAddress.city || '',
                state: user.deliveryAddress.state || '',
                zipCode: user.deliveryAddress.zipCode || ''
            });
        }
        if (user) {
            setProfileDetails({
                name: user.name || '',
                phone: user.phone || ''
            });
        }
    }, [user]);

    const fetchGrievances = async () => {
        try {
            const res = await fetch(`http://localhost:7000/api/admin/messages`); // Using admin route for simple fetch
            if (res.ok) {
                const all = await res.json();
                setGrievances(all.filter(m => m.customerEmail === user.email));
            }
        } catch (err) {
            console.error(err);
        }
    };

    // Real order history should be fetched securely, displaying empty for now
    const orders = [];

    const handleViewInvoice = (order) => {
        setSelectedOrder(order);
        setIsInvoiceOpen(true);
    };

    const handleSendMessage = async () => {
        if (!messageText.trim()) return;
        setIsSending(true);
        try {
            const res = await fetch('http://localhost:7000/api/messages', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    customerName: user?.name || 'Guest',
                    customerEmail: user?.email || 'guest@example.com',
                    message: messageText
                })
            });
            if (res.ok) {
                alert('Your message has been sent to Venthulir Support.');
                setMessageText('');
                setIsMessageModalOpen(false);
                fetchGrievances();
            } else {
                alert('Failed to send message.');
            }
        } catch (err) {
            console.error(err);
            alert('Error sending message.');
        } finally {
            setIsSending(false);
        }
    };

    const handleUpdateAddress = async (e) => {
        e.preventDefault();
        setIsUpdatingAddress(true);
        try {
            const res = await fetch('http://localhost:7000/api/auth/address', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('venthulir_token')}`
                },
                body: JSON.stringify(profileAddress)
            });
            if (res.ok) {
                const data = await res.json();
                updateUser({ ...user, deliveryAddress: data.deliveryAddress });
                alert('Your delivery address has been successfully updated.');
            } else {
                alert('Failed to update address.');
            }
        } catch (err) {
            console.error(err);
            alert('Error updating address.');
        } finally {
            setIsUpdatingAddress(false);
        }
    };

    const handleUpdateProfile = async (e) => {
        e.preventDefault();
        setIsUpdatingProfile(true);
        try {
            const res = await fetch('http://localhost:7000/api/auth/profile', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('venthulir_token')}`
                },
                body: JSON.stringify(profileDetails)
            });
            if (res.ok) {
                const data = await res.json();
                updateUser(data.user);
                alert('Your profile has been successfully updated.');
            } else {
                alert('Failed to update profile.');
            }
        } catch (err) {
            console.error(err);
            alert('Error updating profile.');
        } finally {
            setIsUpdatingProfile(false);
        }
    };

    return (
        <div className="cp-wrapper">
            <div className="cp-container">

                {/* Dashboard Grid View */}
                {activeSection === 'Dashboard' && (
                    <>
                        <div className="cp-header">
                            <h1 className="cp-title">Your Account</h1>
                        </div>
                        <div className="cp-grid">
                            <div className="cp-card-box" onClick={() => setActiveSection('Your Orders')}>
                                <div className="cp-card-icon"><Package size={24} /></div>
                                <div className="cp-card-content">
                                    <h3>Your Orders</h3>
                                    <p>Track, return, or buy things again</p>
                                </div>
                            </div>
                            <div className="cp-card-box" onClick={() => setActiveSection('Login & Security')}>
                                <div className="cp-card-icon"><Settings size={24} /></div>
                                <div className="cp-card-content">
                                    <h3>Login & security</h3>
                                    <p>Edit login, name, and mobile number</p>
                                </div>
                            </div>
                            <div className="cp-card-box" onClick={() => setActiveSection('Your Addresses')}>
                                <div className="cp-card-icon"><FileText size={24} /></div>
                                <div className="cp-card-content">
                                    <h3>Your Addresses</h3>
                                    <p>Edit delivery addresses for orders</p>
                                </div>
                            </div>
                            <div className="cp-card-box" onClick={() => setActiveSection('Customer Service')}>
                                <div className="cp-card-icon"><ShieldQuestion size={24} /></div>
                                <div className="cp-card-content">
                                    <h3>Customer Service</h3>
                                    <p>Browse help topics, track complaints</p>
                                </div>
                            </div>
                            {(user?.isAdmin || user?.email === 'shreenithya111@gmail.com') && (
                                <div className="cp-card-box" onClick={() => (window.location.href = '/admin')}>
                                    <div className="cp-card-icon" style={{ backgroundColor: '#eef2ff', color: '#4f46e5' }}><LayoutDashboard size={24} /></div>
                                    <div className="cp-card-content">
                                        <h3 style={{ color: '#4f46e5' }}>Admin Panel</h3>
                                        <p>Manage products, orders, and users</p>
                                    </div>
                                </div>
                            )}

                            <div className="cp-card-box" onClick={logout}>
                                <div className="cp-card-icon" style={{ backgroundColor: '#fff0f0', color: '#B12704' }}><LogOut size={24} /></div>
                                <div className="cp-card-content">
                                    <h3 style={{ color: '#B12704' }}>Sign Out</h3>
                                    <p>Securely log out of your account</p>
                                </div>
                            </div>
                        </div>
                    </>
                )}

                {/* Main Content Areas */}
                {activeSection !== 'Dashboard' && (
                    <div className="cp-breadcrumb">
                        <span onClick={() => setActiveSection('Dashboard')}>Your Account</span> ΓÇ║ {activeSection}
                    </div>
                )}

                {activeSection === 'Your Orders' && (
                    <div>
                        <div className="cp-header">
                            <h1 className="cp-title">Your Orders</h1>
                        </div>

                        <div className="cp-order-list">
                            {orders.length === 0 ? (
                                <div style={{ textAlign: 'center', padding: '40px', background: '#fff', borderRadius: '8px', border: '1px solid #ddd' }}>
                                    <Package size={48} style={{ color: '#ccc', margin: '0 auto 15px' }} />
                                    <h3 style={{ fontSize: '18px', color: '#111', margin: '0 0 10px 0' }}>Looks like you haven't placed an order yet.</h3>
                                    <p style={{ color: '#555', fontSize: '14px', margin: 0 }}>Start filling your basket with fresh organic goods.</p>
                                </div>
                            ) : (
                                orders.map((order) => (
                                    <motion.div
                                        key={order.id}
                                        initial={{ opacity: 0, y: 20 }}
                                        whileInView={{ opacity: 1, y: 0 }}
                                        viewport={{ once: true }}
                                        className="cp-order-card"
                                    >
                                        <div className="cp-order-meta">
                                            <div className="cp-order-stats">
                                                <div>
                                                    <p className="cp-meta-label">Order Placed</p>
                                                    <p className="cp-meta-value">{order.date}</p>
                                                </div>
                                                <div>
                                                    <p className="cp-meta-label">Total</p>
                                                    <p className="cp-meta-value">Γé╣{order.total}</p>
                                                </div>
                                                <div>
                                                    <p className="cp-meta-label">Order #</p>
                                                    <p className="cp-meta-value">{order.id}</p>
                                                </div>
                                            </div>
                                            <button onClick={() => handleViewInvoice(order)} className="cp-invoice-btn">
                                                View Invoice
                                            </button>
                                        </div>

                                        <div className="cp-order-body">
                                            <div className="cp-order-status-header">
                                                <div className="cp-status-title">
                                                    Status: {order.status}
                                                </div>
                                                <button onClick={() => setIsMessageModalOpen(true)} className="cp-assist-btn">Get Product Support</button>
                                            </div>

                                            <OrderTracking status={order.status} />

                                            <div className="cp-order-items">
                                                {order.items.map((item, idx) => (
                                                    <div key={idx} className="cp-item-row">
                                                        <div className="cp-item-icon"><ShoppingBag size={24} /></div>
                                                        <div className="cp-item-details">
                                                            <p className="cp-item-name">{item.name}</p>
                                                            <p className="cp-item-price">Γé╣{item.price}</p>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </motion.div>
                                ))
                            )}
                        </div>
                    </div>
                )}

                {activeSection === 'Customer Service' && (
                    <div>
                        <div className="cp-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h1 className="cp-title">Customer Service</h1>
                            <button
                                onClick={() => setIsMessageModalOpen(true)}
                                className="cp-btn-primary"
                                style={{ marginTop: 0 }}
                            >
                                Contact Us
                            </button>
                        </div>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                            {grievances.map((g) => (
                                <div key={g._id} className="cp-card" style={{ maxWidth: '100%' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
                                        <div>
                                            <p style={{ fontSize: '12px', color: '#555', marginBottom: '5px' }}>Status: {g.status}</p>
                                            <h3 style={{ fontSize: '16px', color: '#111', margin: 0 }}>{new Date(g.createdAt).toLocaleDateString()}</h3>
                                        </div>
                                        <div style={{ padding: '4px 10px', borderRadius: '4px', fontSize: '11px', fontWeight: 'bold', textTransform: 'uppercase', background: g.status === 'Open' ? '#fcf4d9' : '#e6f4ea', color: g.status === 'Open' ? '#B8860B' : '#137333' }}>
                                            {g.status}
                                        </div>
                                    </div>
                                    <div style={{ backgroundColor: '#f9f9f9', padding: '15px', borderRadius: '4px', marginBottom: '15px', border: '1px solid #eee' }}>
                                        <p style={{ fontSize: '14px', color: '#333', margin: 0 }}>"{g.message}"</p>
                                    </div>
                                    {g.reply && (
                                        <div style={{ borderTop: '1px solid #ddd', paddingTop: '15px' }}>
                                            <p style={{ fontSize: '12px', fontWeight: 'bold', color: '#555', marginBottom: '5px' }}>Follow-up Response</p>
                                            <p style={{ fontSize: '14px', color: '#111', margin: 0 }}>{g.reply}</p>
                                        </div>
                                    )}
                                </div>
                            ))}
                            {grievances.length === 0 && (
                                <div style={{ textAlign: 'center', padding: '40px', background: '#fff', borderRadius: '8px', border: '1px solid #ddd' }}>
                                    <ShieldQuestion size={48} style={{ color: '#ccc', margin: '0 auto 15px' }} />
                                    <h3 style={{ fontSize: '18px', color: '#111', margin: '0 0 10px 0' }}>No active cases.</h3>
                                    <p style={{ color: '#555', fontSize: '14px', margin: 0 }}>Your inquiries and complaints will be listed here.</p>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {activeSection === 'Login & Security' && (
                    <div>
                        <div className="cp-header">
                            <h1 className="cp-title">Login & Security</h1>
                        </div>

                        <div className="cp-card">
                            <h3 style={{ fontSize: '18px', margin: '0 0 20px 0', color: '#111' }}>Edit Profile Information</h3>
                            <form onSubmit={handleUpdateProfile}>
                                <div className="cp-form-row">
                                    <label className="cp-input-label">Full Name</label>
                                    <input
                                        type="text"
                                        required
                                        className="cp-input"
                                        value={profileDetails.name}
                                        onChange={e => setProfileDetails({ ...profileDetails, name: e.target.value })}
                                        placeholder="Your full name"
                                    />
                                </div>
                                <div className="cp-form-row">
                                    <label className="cp-input-label">Email Address</label>
                                    <input
                                        type="text"
                                        readOnly
                                        disabled
                                        className="cp-input"
                                        value={user?.email || ''}
                                        style={{ background: '#f0f0f0', color: '#777', cursor: 'not-allowed' }}
                                    />
                                    <span style={{ fontSize: '11px', color: '#555' }}>Email address cannot be changed.</span>
                                </div>
                                <div className="cp-form-row">
                                    <label className="cp-input-label">Mobile Number</label>
                                    <input
                                        type="text"
                                        required
                                        className="cp-input"
                                        value={profileDetails.phone}
                                        onChange={e => setProfileDetails({ ...profileDetails, phone: e.target.value })}
                                        placeholder="Secure contact number"
                                    />
                                </div>

                                <button
                                    type="submit"
                                    disabled={isUpdatingProfile}
                                    className="cp-btn-primary"
                                >
                                    {isUpdatingProfile ? 'Saving...' : 'Save Profile Details'}
                                </button>
                            </form>
                        </div>
                    </div>
                )}

                {activeSection === 'Your Addresses' && (
                    <div>
                        <div className="cp-header">
                            <h1 className="cp-title">Your Addresses</h1>
                        </div>

                        <div className="cp-card">
                            <h3 style={{ fontSize: '18px', margin: '0 0 20px 0', color: '#111' }}>Default Delivery Address</h3>
                            <form onSubmit={handleUpdateAddress}>
                                <div className="cp-form-row">
                                    <label className="cp-input-label">Street Address</label>
                                    <input
                                        type="text"
                                        required
                                        className="cp-input"
                                        value={profileAddress.address}
                                        onChange={e => setProfileAddress({ ...profileAddress, address: e.target.value })}
                                        placeholder="House/Flat No., Street, Area"
                                    />
                                </div>
                                <div className="cp-form-group">
                                    <div className="cp-form-row">
                                        <label className="cp-input-label">City</label>
                                        <input
                                            type="text"
                                            required
                                            className="cp-input"
                                            value={profileAddress.city}
                                            onChange={e => setProfileAddress({ ...profileAddress, city: e.target.value })}
                                        />
                                    </div>
                                    <div className="cp-form-row">
                                        <label className="cp-input-label">State</label>
                                        <input
                                            type="text"
                                            required
                                            className="cp-input"
                                            value={profileAddress.state}
                                            onChange={e => setProfileAddress({ ...profileAddress, state: e.target.value })}
                                        />
                                    </div>
                                </div>
                                <div className="cp-form-row">
                                    <label className="cp-input-label">ZIP Code</label>
                                    <input
                                        type="text"
                                        required
                                        className="cp-input"
                                        value={profileAddress.zipCode}
                                        onChange={e => setProfileAddress({ ...profileAddress, zipCode: e.target.value })}
                                    />
                                </div>

                                <button
                                    type="submit"
                                    disabled={isUpdatingAddress}
                                    className="cp-btn-primary"
                                >
                                    {isUpdatingAddress ? 'Saving Changes...' : 'Save Default Address'}
                                </button>
                            </form>
                        </div>
                    </div>
                )}
            </div>

            <InvoiceModal
                isOpen={isInvoiceOpen}
                onClose={() => setIsInvoiceOpen(false)}
                orderData={selectedOrder}
            />

            {/* Assistance Modal */}
            <AnimatePresence>
                {isMessageModalOpen && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        style={{ position: 'fixed', inset: 0, zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(4px)' }}
                    >
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.95, opacity: 0 }}
                            style={{ background: '#fff', padding: '30px', borderRadius: '16px', width: '90%', maxWidth: '500px', boxShadow: '0 20px 40px rgba(0,0,0,0.2)' }}
                        >
                            <h2 style={{ fontSize: '18px', fontWeight: 'bold', color: '#111', marginBottom: '15px' }}>Contact Venthulir Support</h2>
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '13px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Your Email</label>
                                <input
                                    type="email"
                                    value={user?.email || ''}
                                    readOnly
                                    style={{ width: '100%', padding: '8px 10px', borderRadius: '3px', border: '1px solid #ddd', background: '#f5f5f5', color: '#555', boxSizing: 'border-box' }}
                                />
                            </div>

                            <div style={{ marginBottom: '20px' }}>
                                <label style={{ fontSize: '13px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Message / Complaint</label>
                                <textarea
                                    value={messageText}
                                    onChange={(e) => setMessageText(e.target.value)}
                                    placeholder="Describe your issue in detail..."
                                    style={{ width: '100%', padding: '10px', borderRadius: '3px', border: '1px solid #888', minHeight: '120px', fontSize: '14px', outline: 'none', boxSizing: 'border-box' }}
                                />
                            </div>

                            <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end' }}>
                                <button
                                    onClick={() => setIsMessageModalOpen(false)}
                                    style={{ padding: '8px 16px', borderRadius: '8px', color: '#0F1111', backgroundColor: '#fff', border: '1px solid #d5d9d9', fontSize: '13px', cursor: 'pointer' }}
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleSendMessage}
                                    disabled={isSending || !messageText.trim()}
                                    style={{ padding: '8px 16px', borderRadius: '8px', background: '#FFD814', border: '1px solid #FCD200', color: '#0F1111', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '8px', opacity: (isSending || !messageText.trim()) ? 0.6 : 1, cursor: 'pointer' }}
                                >
                                    {isSending ? 'Sending...' : <><Send size={16} /> Send Message</>}
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div >
    );
};

export default CustomerPage;

